import{_ as i,o as a,c as e,ai as r}from"./chunks/framework.CaiDwmc7.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"03 Левел-дизайн/Центральная локация.md","filePath":"03 Левел-дизайн/Центральная локация.md"}'),_={name:"03 Левел-дизайн/Центральная локация.md"};function t(n,l,o,h,p,s){return a(),e("div",null,[...l[0]||(l[0]=[r('<h4 id="планировка-пасеки" tabindex="-1">Планировка пасеки <a class="header-anchor" href="#планировка-пасеки" aria-label="Permalink to “Планировка пасеки”">​</a></h4><ul><li>[ ] Определить места для: дома, ульев, спавна игрока, НПС, тропинок между объектами</li><li>[ ] Разместить зоны сбора для пчел</li><li>[ ] Точки интереса (колодец, инструменты, стол и тп)</li></ul><h4 id="арт-пасеки" tabindex="-1">Арт пасеки <a class="header-anchor" href="#арт-пасеки" aria-label="Permalink to “Арт пасеки”">​</a></h4><ul><li>[ ] Фон/террейн пасеки</li><li>[ ] Дом (фасад)</li><li>[ ] Ульи</li><li>[ ] Цветы, трава, декор</li><li>[ ] Забор</li><li>[ ] Тропинки</li><li>[ ] Детали (ведро, дымарь, телега и тп)</li></ul><h4 id="аудио-пасеки" tabindex="-1">Аудио пасеки <a class="header-anchor" href="#аудио-пасеки" aria-label="Permalink to “Аудио пасеки”">​</a></h4><ul><li>[ ] Атмосферный фон (жужжание, птицы, ветер)</li><li>[ ] Звуки шагов по траве/земле</li></ul><h4 id="сборка-пасеки" tabindex="-1">Сборка пасеки <a class="header-anchor" href="#сборка-пасеки" aria-label="Permalink to “Сборка пасеки”">​</a></h4><ul><li>[ ] Собрать локацию в движке</li><li>[ ] Настроить коллизии</li><li>[ ] Добавить триггеры переходов</li></ul><h4 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to “Описание”">​</a></h4><ol><li>Игровое пространство (локация)</li></ol><p>Задний двор дома и прилегающий луг.</p><ul><li><p>Дом: Неигровой в рамках вертикального среза. Геймплей внутри дома в планах.<br> Рядом с домом: зона для работы (стол, место для инвентаря, навес).</p></li><li><p>Пасечная площадка: 3-5 подставок под ульи. Игрок может свободно их расставлять, учитывая ориентацию (летки на юг/восток).</p></li><li><p>Окружение: Несколько типов растительности с визуальными маркерами:</p></li><li><p>Медоносы: Небольшая цветущая липовая аллея, участок цветущего клевера на лугу, несколько кустов садового вереска.</p></li><li><p>Ресурсы: Источник воды (ручей или поилка для пчёл), который нужно наполнять.</p></li><li><p>Погода и время: Полный цикл смены дня и ночи, динамическая погода (солнце, облака, мелкий дождь, ветер). Влияет на поведение пчёл.</p></li></ul><p>**</p>',13)])])}const u=i(_,[["render",t]]);export{c as __pageData,u as default};
